import{_ as t,o as e,c as s,S as n}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"面试官问：深度学习与传统机器学习的核心区别？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_3-deep_learning.md","filePath":"面试官问/17ai/q_ai_3-deep_learning.md","lastUpdated":1778207238000}'),r={name:"面试官问/17ai/q_ai_3-deep_learning.md"};function i(l,a,p,d,o,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="面试官问-深度学习与传统机器学习的核心区别" tabindex="-1">面试官问：深度学习与传统机器学习的核心区别？ <a class="header-anchor" href="#面试官问-深度学习与传统机器学习的核心区别" aria-label="Permalink to &quot;面试官问：深度学习与传统机器学习的核心区别？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_3-deep_learning.html">深度学习</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_4-neural_network.html">神经网络</a></p></blockquote><p><strong>考察点</strong>：特征提取方式的核心差异（人工 vs 自动）、CNN/RNN/Transformer 架构对比、深度学习爆发的三大驱动力</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>深度学习是机器学习的子集，核心区别在于<strong>特征提取方式</strong>：</p><table><thead><tr><th>维度</th><th>传统 ML</th><th>深度学习</th></tr></thead><tbody><tr><td><strong>特征提取</strong></td><td>人工设计（专家经验）</td><td>自动学习（端到端）</td></tr><tr><td><strong>模型结构</strong></td><td>浅层（1-3 层）</td><td>深层（数十~数百层）</td></tr><tr><td><strong>数据需求</strong></td><td>小数据集可用</td><td>需要海量数据</td></tr><tr><td><strong>可解释性</strong></td><td>相对可解释</td><td>&quot;黑盒&quot;难解释</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>核心架构对比：</span></span>
<span class="line"><span>├── DNN (深度神经网络)：全连接，通用</span></span>
<span class="line"><span>├── CNN (卷积神经网络)：图像识别，局部特征提取</span></span>
<span class="line"><span>├── RNN/LSTM/GRU：序列处理，时间依赖</span></span>
<span class="line"><span>└── Transformer：自注意力，并行计算（LLM 基础）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>为什么深度学习在 2012 年后爆发</strong>？</p><ul><li>📊 大数据：互联网积累了海量标注数据</li><li>💻 算力：GPU 并行计算使深层网络训练成为可能</li><li>🔧 算法：ReLU、BatchNorm、ResNet 解决梯度消失问题</li></ul><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>记住&quot;人工提取特征 vs 自动学习特征&quot;这个核心差异</li><li>至少说出 CNN/RNN/Transformer 三种架构和适用场景</li><li>能说明深度学习爆发的三个驱动力</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_3-deep_learning.html">深度学习概念讲解</a></p></blockquote>`,5)])])}const b=t(r,[["render",i]]);export{u as __pageData,b as default};
